class Solution {
    public int flipLights(int n, int presses) {
        if (presses == 0) return 1;
        if (n == 1) return 2;
        if (n == 2) {
            if (presses == 1) return 3;
            return presses % 2 == 0 ? 4 : 3;
        }
        if (presses == 1) return 4;
        if (presses == 2) return 7;
        if (presses >= 3 && n >= 3) return presses % 2 == 0 ? 8 : 4;
        return 0;
    }
}
